#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char S[105]; scanf("%s", S);
        int firstZero = -1;
        for (int i = 0; i < N; ++i) {
            if (S[i] == '0') { firstZero = i; break; }
        }
        for (int i = 0; i < N; ++i) {
            if (firstZero == -1) {
                if (i == N-1) printf("YES\n");
                else printf("IDK\n");
            } else {
                if (i < firstZero) printf("IDK\n");
                else printf("NO\n");
            }
        }
    }
    return 0;
}

