import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        S = next(it)
        first_zero = S.find('0')
        if first_zero == -1:
            for i in range(N):
                out_lines.append('YES' if i == N-1 else 'IDK')
        else:
            for i in range(N):
                out_lines.append('IDK' if i < first_zero else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

